def direction_8way(dx, dy, threshold=1e-6):
    """
    Convert a 2D displacement into one of 8 compass directions plus NC.
    Direction is metadata only; it must not gate participation.
    """
    if abs(dx) < threshold and abs(dy) < threshold:
        return 'NC'

    angle = np.degrees(np.arctan2(dy, dx))

    if -22.5 <= angle < 22.5:
        return 'E'
    if 22.5 <= angle < 67.5:
        return 'NE'
    if 67.5 <= angle < 112.5:
        return 'N'
    if 112.5 <= angle < 157.5:
        return 'NW'
    if angle >= 157.5 or angle < -157.5:
        return 'W'
    if -157.5 <= angle < -112.5:
        return 'SW'
    if -112.5 <= angle < -67.5:
        return 'S'
    if -67.5 <= angle < -22.5:
        return 'SE'

    return 'NC'
